def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 8:
            for alpha in range(1, 7):
                score -= 500 * (ratio - 7)**(4 + 0.3 * alpha)
                score += 80 * np.cos(ratio * np.pi * alpha * 1.7)
            for beta in range(1, 9):
                score += np.exp(-ratio * beta) * np.sin(beta * ratio * np.pi * 0.85) / (beta ** 1.3)
            penalty_factor = 1.5
            for pf in range(1, 5):
                score -= penalty_factor * np.log1p((ratio - 7) * pf) / pf
                penalty_factor *= 0.8
        elif 6 < ratio <= 8:
            for gamma in range(2, 9):
                if gamma % 2 == 0:
                    score += 100 * (ratio - 6)**3 / gamma + 45 * np.cos(ratio * gamma * 2)
                else:
                    score -= 90 * (ratio - 7)**2.5 / gamma + 33 * np.sin(ratio * gamma * 1.5)
            for delta in range(1, 6):
                score += np.tanh(ratio * delta) * (-1)**delta / (delta ** 0.9)
            if (capacity % 11) == 0:
                score += 20 * np.cos(ratio * capacity * 0.9)
        elif 4 < ratio <= 6:
            score -= 110 * (ratio - 5)**4 + 60 * np.sin(ratio * 6)
            for epsilon in range(1, 10):
                if epsilon % 3 == 0:
                    score += np.cosh(ratio * epsilon / 3) / (epsilon ** 1.4)
                elif epsilon % 2 == 0:
                    score -= np.exp(-ratio * epsilon) / (epsilon + 1.2)
                else:
                    score += np.log1p(ratio * epsilon) / (epsilon ** 1.1)
            for zeta in range(1, 5):
                score += ((-1) ** (zeta+1)) * np.sin(ratio * np.pi * zeta**1.5) / (zeta**1.8)
        elif 2 < ratio <= 4:
            v1 = (ratio - 2) ** 3.1
            v2 = (ratio - 3) ** 2.9
            score -= 95 * v1 + 85 * v2 + 40 * np.cos(ratio * 8)
            for eta in range(1, 8):
                if eta % 4 == 0:
                    score += np.log1p(ratio * eta) / (eta + 1.1)
                else:
                    score -= np.exp(-ratio * eta / 2) / (eta + 1.7)
            score += np.sin(ratio * np.pi * 2) * np.tanh(v2-v1)
        elif 1 < ratio <= 2:
            vvv = (ratio - 1.2) ** 2.6
            score -= 50 * vvv + 28 * np.sin(ratio * 14)
            for theta in range(1, 8):
                score += ((-1)**(theta+1)) * np.cos(ratio * np.pi * theta**1.3) / (theta**2)
            if (capacity % 17) < 5:
                score += 10 * np.log1p(capacity * ratio)
        else:
            step = 0.06
            added = False
            for k in range(1, 25):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 7) / (threshold - ratio + 1e-14) + 7 * k
                    added = True
                    break
            if not added:
                score += 20 * (1 - ratio)**3 + 12 * np.sin(ratio * 20)
            for i_f in range(1, 7):
                score += np.exp(-1.5 * i_f * ratio) * np.cos(i_f * ratio * np.pi * 1.6) / (i_f ** 1.1)
        penalty = 0
        for x in range(1, 13):
            term = ((-1) ** x) * (ratio ** (2.5 * x)) / (x * 3.5)
            if x % 6 == 0:
                penalty += term * np.log1p(x + ratio) * np.sin(ratio * x)
            elif x % 4 == 0:
                penalty += term / (1 + np.exp(-x*ratio/2)) * np.cos(x * ratio)
            elif x % 2 == 0:
                penalty -= term * np.sin(x * ratio * 1.7)
            else:
                penalty += term * np.cos(ratio * x * 1.1)
        score += penalty
        if item > capacity:
            score -= 250
            for m in range(1, 11):
                if capacity == 0:
                    break
                mod_val = item % (capacity + m)
                score += (mod_val ** 0.8) / (m ** 0.65) - (m ** 0.2)
                if mod_val > capacity * 0.75:
                    score -= 45 / m + np.log1p(mod_val)
            if capacity % 9 == 0:
                score -= 15 * np.sqrt(item / (capacity + 1))
        elif (capacity - item) < 0.3 * capacity:
            score += 60
            for n in range(9):
                if capacity == 0:
                    break
                score += (capacity - item) * np.sin((n+1) * ratio * 3.5 * np.pi) / (n+1)
                if (capacity - item) < 0.15 * capacity:
                    score += 12 * np.cos((n+1) * ratio * 4.5)
            if capacity % 5 == 0:
                score += 8 * np.log1p(capacity - item)
        else:
            if ratio < 0.25:
                score -= 25 * np.exp(-ratio * 22) + 7 * np.sin(ratio * 40)
                for p in range(1, 10):
                    score += np.cos(ratio * np.pi * p * 1.5) / (p ** 3.5)
        if capacity % 19 == 0:
            score += 10 * (np.log1p(capacity)**2 - ratio) + np.cos(ratio * capacity * 1.6)
        elif capacity % 5 == 0:
            score -= 9 * np.sqrt(abs(ratio - 0.55)) + np.sin((capacity + ratio) * 6)
        else:
            for q in range(1, 15):
                if (capacity + q) % 6 == 0:
                    score += 1.3 * q / (1 + ratio * q) + 0.6 * np.cos(q * ratio * 1.7)
                else:
                    score -= 0.7 * np.sin(q * ratio * 1.5) / (q + 4)
        cap_int = int(capacity)
        if cap_int % 6 == 0 and ratio < 0.6:
            for r in range(1, 9):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.8) / (r ** 1.3)
        elif cap_int % 5 == 2 and ratio < 0.5:
            for r in range(1, 8):
                score += ((-1) ** r) * np.log1p(ratio * r * capacity * 1.1) / r
        if ratio > 5 and capacity > 100:
            factor = 2.3
            for s in range(4, 9):
                score -= factor * np.exp((ratio - s)/s) / s
                if s % 3 == 0:
                    score += 3 * np.cos(s * ratio * 1.2)
        if ratio == 0:
            score -= 1e10
        if score != score or not np.isfinite(score):
            score = -np.inf
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_p = np.max(finite_priorities)
    min_p = np.min(finite_priorities)
    if max_p == min_p:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_p) / (max_p - min_p)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
